from fathom.lib.util_rolling_outliers import rolling_outliers

decimal_accuracy = 12

def test_rolling_outliers_empty_list():
    # SETUP

    # RUN
    result = rolling_outliers([])

    # VERIFY
    assert len(result['lower_data']) == 0
    assert len(result['upper_data']) == 0
    assert len(result['outliers_data']) == 0

def test_rolling_outliers_consistent_data():
    # SETUP
    data = [('2021-09-{:02}'.format(i+1), 1) for i in range(10)]

    # RUN
    result = rolling_outliers(data)

    # VERIFY
    assert (result['lower_data']) == data
    assert (result['upper_data']) == data
    assert (result['outliers_data']) == []

